import re

_NUMBER_RE = re.compile(r"\d+(?:\.\d*)?|\.\d+")


def _tokenize(expr):
    tokens = []
    i = 0
    n = len(expr)
    while i < n:
        c = expr[i]
        if c.isspace():
            i += 1
        elif c.isdigit() or c == ".":
            m = _NUMBER_RE.match(expr, i)
            if m is None:
                raise ValueError(f"invalid number at position {i}")
            tokens.append(("num", float(m.group())))
            i = m.end()
        elif expr.startswith("**", i):
            tokens.append(("op", "**"))
            i += 2
        elif c in "+-*/()":
            tokens.append(("op", c))
            i += 1
        else:
            raise ValueError(f"illegal character {c!r} at position {i}")
    return tokens


class _Parser:
    def __init__(self, tokens):
        self.tokens = tokens
        self.pos = 0

    def _peek_op(self):
        if self.pos < len(self.tokens):
            kind, value = self.tokens[self.pos]
            if kind == "op":
                return value
        return None

    def parse_expr(self):
        value = self.parse_term()
        while self._peek_op() in ("+", "-"):
            op = self.tokens[self.pos][1]
            self.pos += 1
            right = self.parse_term()
            value = value + right if op == "+" else value - right
        return value

    def parse_term(self):
        value = self.parse_unary()
        while self._peek_op() in ("*", "/"):
            op = self.tokens[self.pos][1]
            self.pos += 1
            right = self.parse_unary()
            value = value * right if op == "*" else value / right
        return value

    def parse_unary(self):
        if self._peek_op() == "-":
            self.pos += 1
            return -self.parse_unary()
        return self.parse_power()

    def parse_power(self):
        base = self.parse_atom()
        if self._peek_op() == "**":
            self.pos += 1
            # right-associative; exponent may carry its own unary minus
            return base ** self.parse_unary()
        return base

    def parse_atom(self):
        if self.pos >= len(self.tokens):
            raise ValueError("unexpected end of expression")
        kind, value = self.tokens[self.pos]
        if kind == "num":
            self.pos += 1
            return value
        if value == "(":
            self.pos += 1
            inner = self.parse_expr()
            if self._peek_op() != ")":
                raise ValueError("unbalanced parentheses: missing ')'")
            self.pos += 1
            return inner
        raise ValueError(f"unexpected token {value!r}")


def evaluate(expr: str) -> float:
    tokens = _tokenize(expr)
    parser = _Parser(tokens)
    result = parser.parse_expr()
    if parser.pos != len(tokens):
        raise ValueError(f"unexpected token {parser.tokens[parser.pos][1]!r}")
    return float(result)
